"use strict";(globalThis.webpackChunkwww=globalThis.webpackChunkwww||[]).push([[3077],{5391(e,t,n){n.r(t),n.d(t,{assets:()=>l,contentTitle:()=>s,default:()=>h,frontMatter:()=>r,metadata:()=>a,toc:()=>c});var a=n(8082),o=n(4848),i=n(8453);const r={title:"SkipLabs Launches Skipper, The Runtime for the Era of AI-Generated Software",description:"From the creator of Hack, the language behind Facebook\u2019s business logic, comes a closed-loop coding agent that turns one prompt into running software.",slug:"press_release",date:new Date("2026-06-01T00:00:00.000Z"),authors:"jverlaguet",image:"/img/og/press_release.png"},s="SkipLabs Launches Skipper: The Runtime for the Era of AI-Generated Software",l={authorsImageUrls:[void 0]},c=[{value:"The Missing Link in AI Coding",id:"the-missing-link-in-ai-coding",level:2},{value:"Fixing State and Concurrency",id:"fixing-state-and-concurrency",level:2},{value:"What Ships Today",id:"what-ships-today",level:2},{value:"The Product Roadmap",id:"the-product-roadmap",level:2},{value:"Who Skipper is For",id:"who-skipper-is-for",level:2},{value:"A Decade Making Code Provably Correct",id:"a-decade-making-code-provably-correct",level:2},{value:"About SkipLabs",id:"about-skiplabs",level:2}];function d(e){const t={a:"a",blockquote:"blockquote",em:"em",h2:"h2",p:"p",strong:"strong",...(0,i.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(t.p,{children:"From the creator of Hack, the language behind Facebook\u2019s business logic, comes a closed-loop coding agent that turns one prompt into running software."}),"\n",(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.strong,{children:"PARIS, FRANCE \u2014 June 1, 2026"})," \u2014 SkipLabs today launched Skipper, a closed-loop coding agent that takes a single prompt and returns a running, validated service. Skipper was built by Julien Verlaguet, creator of Facebook's Hack programming language, alongside a team of engineers drawn from Facebook, Microsoft, Microsoft Research, Meta and the broader systems community. It serves as the architectural layer sitting between AI models and shipped software.\nSkipper is designed specifically for technical builders: product managers running their own AI workflows, engineering teams shipping production services, and developers who demand architectural discipline without architectural overhead."]}),"\n",(0,o.jsx)(t.h2,{id:"the-missing-link-in-ai-coding",children:"The Missing Link in AI Coding"}),"\n",(0,o.jsx)(t.p,{children:"Skipper arrives at a critical inflection point. While AI coding tools have made the first draft of a service nearly free, what remains is the gap between almost running and actually running in production. This is an architecture problem\u2014one that doesn't disappear just because a language model gets smarter."}),"\n",(0,o.jsxs)(t.blockquote,{children:["\n",(0,o.jsx)(t.p,{children:'"Building correct software has always been an architecture problem disguised as a coding problem," said Julien Verlaguet, Founder and CEO of SkipLabs. "AI did not change that; it just made the problem more urgent."\nSkipper sits beneath the foundation models. Rather than competing with Claude, GPT, or Gemini, it acts as the substrate that turns their output into finished software rather than a draft awaiting review. When a builder describes the service they want, Skipper handles the entire pipeline autonomously: decomposing the work into manageable pieces, routing each piece to the specific AI model best suited for that task, generating and validating the code, and returning a reliable, running service. No developer review, no oversight cycles, no back-and-forth.'}),"\n"]}),"\n",(0,o.jsx)(t.h2,{id:"fixing-state-and-concurrency",children:"Fixing State and Concurrency"}),"\n",(0,o.jsx)(t.p,{children:"State management and concurrency are the hardest parts of writing correct software, and the exact areas where AI most often produces broken code.\nSkipper solves this via its reactive runtime\u2014drawn from the open-source Skip framework Verlaguet built at Facebook in 2017. Because the runtime automatically handles state management and concurrency, the AI model never has to reason about cause and effect across a sprawling state graph. By shrinking the surface area where AI can make mistakes, Skipper ensures more of what it produces actually works."}),"\n",(0,o.jsxs)(t.blockquote,{children:["\n",(0,o.jsx)(t.p,{children:'"Closed loop is not a feature," Verlaguet added. "It is a different theory of what an AI coding tool is supposed to do. The current generation makes the developer faster. The next generation makes the developer\'s involvement optional. Describe what you want and Skipper builds it."'}),"\n"]}),"\n",(0,o.jsx)(t.h2,{id:"what-ships-today",children:"What Ships Today"}),"\n",(0,o.jsx)(t.p,{children:"Launching today, Skipper delivers the core closed-loop experience: a single prompt becomes a running service. A model-agnostic harness routes each task to the AI model best suited for it, with no lock-in to any single foundation model. And Skipper-built services integrate with the outside world from day one \u2014 calling external APIs, fetching live data, and posting to other systems to ensure the software fits into a real stack, not just a sandbox."}),"\n",(0,o.jsx)(t.h2,{id:"the-product-roadmap",children:"The Product Roadmap"}),"\n",(0,o.jsx)(t.p,{children:"In the weeks following launch, SkipLabs will roll out SKJS, a sound, TypeScript-compatible type system that lets Skipper understand how changes to one part of the code affect the rest.  Next comes in-place incremental updates, allowing builders to change a specification and have Skipper modify the running service without a full rebuild. By late 2026, SkipLabs will deliver precise, zero-pollution awareness of the full codebase at any scale."}),"\n",(0,o.jsx)(t.h2,{id:"who-skipper-is-for",children:"Who Skipper is For"}),"\n",(0,o.jsx)(t.p,{children:"Skipper is built for those who experience the frustration of watching an AI generate a near-working idea, yet possess the technical knowledge to see exactly why the last 10% breaks. It is designed for technical product managers wiring AI into production tools via real API integrations rather than sandboxed demos. It also serves engineering teams shipping production backend services who want architectural discipline without the per-line review cycle, and software development firms building AI-driven systems for clients whose code absolutely must ship."}),"\n",(0,o.jsx)(t.h2,{id:"a-decade-making-code-provably-correct",children:"A Decade Making Code Provably Correct"}),"\n",(0,o.jsxs)(t.p,{children:["The architecture beneath Skipper predates the current AI coding wave and is backed by over a decade of infrastructure-first philosophy. Verlaguet created Hack, the gradually typed programming language that powers Facebook's business logic and over 100 million lines of production code. Amplify Partners, which led SkipLabs' $8 million seed round, noted in its investment memo that Verlaguet is ",(0,o.jsx)(t.em,{children:'"one of the top two to three programming language designers in the world."'})," His work on programming language design has also been publicly endorsed by Turing Award winner and former Meta Chief AI Scientist Yann LeCun.\n",(0,o.jsxs)(t.strong,{children:["Skipper is available today at ",(0,o.jsx)(t.a,{href:"https://skipperai.dev",children:"skipperai.dev"}),"."]})]}),"\n",(0,o.jsx)(t.h2,{id:"about-skiplabs",children:"About SkipLabs"}),"\n",(0,o.jsxs)(t.p,{children:["SkipLabs builds the infrastructure layer that makes AI-generated code work in production. Founded in 2022 by Julien Verlaguet, creator of Facebook's Hack programming language, the company develops tools that close the loop between intent and running software for technical product managers, engineering teams, and the firms that build production systems on top of AI. SkipLabs is backed by Amplify Partners, with angel investors including Yann LeCun and Spencer Kimball, co-founder and CEO of Cockroach Labs. For more information, visit ",(0,o.jsx)(t.a,{href:"https://skiplabs.io",children:"skiplabs.io"}),"."]})]})}function h(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,o.jsx)(t,{...e,children:(0,o.jsx)(d,{...e})}):d(e)}},8453(e,t,n){n.d(t,{R:()=>r,x:()=>s});var a=n(6540);const o={},i=a.createContext(o);function r(e){const t=a.useContext(i);return a.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function s(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(o):e.components||o:r(e.components),a.createElement(i.Provider,{value:t},e.children)}},8082(e){e.exports=JSON.parse('{"permalink":"/blog/press_release","source":"@site/blog/press_release.md","title":"SkipLabs Launches Skipper, The Runtime for the Era of AI-Generated Software","description":"From the creator of Hack, the language behind Facebook\u2019s business logic, comes a closed-loop coding agent that turns one prompt into running software.","date":"2026-06-01T00:00:00.000Z","tags":[],"readingTime":4.35,"hasTruncateMarker":false,"authors":[{"name":"Julien Verlaguet","title":"SkipLabs Founder & CEO","url":"https://x.com/JulienVerlaguet","key":"jverlaguet","page":null}],"frontMatter":{"title":"SkipLabs Launches Skipper, The Runtime for the Era of AI-Generated Software","description":"From the creator of Hack, the language behind Facebook\u2019s business logic, comes a closed-loop coding agent that turns one prompt into running software.","slug":"press_release","date":"2026-06-01T00:00:00.000Z","authors":"jverlaguet","image":"/img/og/press_release.png"},"unlisted":false,"lastUpdatedAt":1780068375000,"nextItem":{"title":"What a Closed-Loop Coding Agent Actually Is","permalink":"/blog/closed_loop_coding_agent"}}')}}]);